// MARK: - KeychainService

class KeychainService {
    static let shared = KeychainService()
    private init() {}

    func save(key: String, data: Data) -> OSStatus {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]

        SecItemDelete(query as CFDictionary) // Delete any existing item
        return SecItemAdd(query as CFDictionary, nil)
    }

    func load(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: kCFBooleanTrue!,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)

        guard status == errSecSuccess else { return nil }
        return item as? Data
    }

    func delete(key: String) -> OSStatus {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        return SecItemDelete(query as CFDictionary)
    }
}

// MARK: - WalletManager

class WalletManager: ObservableObject {
    @Published var privateKeyData: Data?
    @Published var walletAddress: String?
    @Published var balance: String?

    private let privateKeyKeychainKey = "com.cryptowallet.privateKey"

    init() {
        loadWallet()
    }

    func generateNewWallet() {
        // For a real wallet, this would involve BIP39 mnemonic generation
        // and BIP32/BIP44 HD key derivation for secp256k1.
        // Here, we generate 32 random bytes as a placeholder for a secp256k1 private key.
        var keyData = Data(count: 32)
        let status = keyData.withUnsafeMutableBytes {
            SecRandomCopyBytes(kSecRandomDefault, 32, $0.baseAddress!)
        }

        guard status == errSecSuccess else {
            print("Failed to generate random private key data.")
            return
        }

        privateKeyData = keyData
        saveWallet()
        deriveAddress()
    }

    func loadWallet() {
        if let loadedKeyData = KeychainService.shared.load(key: privateKeyKeychainKey) {
            privateKeyData = loadedKeyData
            deriveAddress()
        } else {
            print("No wallet found in Keychain.")
        }
    }

    private func saveWallet() {
        guard let keyData = privateKeyData else { return }
        let status = KeychainService.shared.save(key: privateKeyKeychainKey, data: keyData)
        if status != errSecSuccess {
            print("Failed to save private key: \(status)")
        } else {
            print("Private key saved successfully.")
        }
    }

    private func deriveAddress() {
        guard let keyData = privateKeyData else {
            walletAddress = nil
            return
        }

        // IMPORTANT: This is a highly simplified placeholder for address derivation.
        // For Ethereum, this involves:
        // 1. Deriving the secp256k1 public key from the private key.
        // 2. Hashing the public key (excluding the 0x04 prefix) with Keccak-256.
        // 3. Taking the last 20 bytes of the hash and prefixing with "0x".
        // This requires a secp256k1 library and Keccak-256 implementation.
        // For this MVP, we'll use a simple SHA256 hash of the private key data
        // and truncate it to simulate an address. This is NOT a real Ethereum address.
        let hash = SHA256.hash(data: keyData)
        let addressBytes = hash.suffix(20) // Take last 20 bytes
        walletAddress = "0x" + addressBytes.map { String(format: "%02x", $0) }.joined()
        print("Derived (dummy) address: \(walletAddress ?? "N/A")")
    }

    func clearWallet() {
        let status = KeychainService.shared.delete(key: privateKeyKeychainKey)
        if status == errSecSuccess {
            privateKeyData = nil
            walletAddress = nil
            balance = nil
            print("Wallet cleared.")
        } else {
            print("Failed to clear wallet: \(status)")
        }
    }
}

// MARK: - TransactionSigner

class TransactionSigner {
    // IMPORTANT: This signing example uses CryptoKit's Curve25519 for demonstration.
    // Ethereum and Bitcoin use secp256k1, which is not directly available in CryptoKit.
    // A real wallet would require a secp256k1 library (e.g., web3.swift, BitcoinKit, or custom implementation).
    func signTransaction(privateKeyData: Data, messageData: Data) -> String? {
        do {
            // For demonstration, we'll use Curve25519.
            // In a real secp256k1 wallet, you'd initialize a secp256k1 private key
            // from privateKeyData and use its signing method.
            let privateKey = try Curve25519.Signing.PrivateKey(rawRepresentation: privateKeyData)
            let signature = try privateKey.signature(for: messageData)
            return signature.rawRepresentation.map { String(format: "%02x", $0) }.joined()
        } catch {
            print("Error signing transaction (using Curve25519 example): \(error)")
            return nil
        }
    }
}

